function geocode(name) {
  if (!name) return { city: '', lat: '', lng: '' };
  const key = String(name).toLowerCase().trim().replace(/[\u2013\u2014\u2212]/g,'-').replace(/\s+/g,' ');
  const hit = CITIES[key];
  const display = key.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  if (hit) return { city: display, lat: hit[0], lng: hit[1] };
  // Unknown city — keep the raw user input as label but leave lat/lng blank;
  // Match-Feed will fall back to a hash hub for visualization.
  return { city: String(name).trim().slice(0, 60), lat: '', lng: '' };
}


let selections = Array.isArray(b.selections) ? b.selections.slice(0, 3) : [];
if (selections.length === 0) {
  const pD = Array.isArray(b.p_deltas) ? b.p_deltas : [];
  const aD = Array.isArray(b.a_deltas) ? b.a_deltas : [];
  const cs = Array.isArray(b.choices) ? b.choices : [];
  for (let i = 0; i < 3; i++) {
    selections.push({
      round: i + 1,
      choice: cs[i] || '',
      p_delta: Number(pD[i]) || 0,
      a_delta: Number(aD[i]) || 0
    });
  }
}
while (selections.length < 3) selections.push({ round: selections.length + 1, choice: '', p_delta: 0, a_delta: 0 });

const pDeltas = selections.map(s => Number(s.p_delta) || 0);
const aDeltas = selections.map(s => Number(s.a_delta) || 0);
const avg = arr => arr.length ? arr.reduce((s,x)=>s+x,0)/arr.length : 0;

const initial_P = num(b.initial_P, 0);
const initial_A = num(b.initial_A, 0);
const final_D = num(b.final_D, 0);

const final_P = +(initial_P + avg(pDeltas) * 0.5).toFixed(4);
const final_A = +(initial_A + avg(aDeltas) * 0.5).toFixed(4);

const rawMode = String(b.match_mode || 'echo').toLowerCase().trim();
const match_mode = (rawMode === 'healing') ? 'healing' : 'echo';

// City: prefer explicit lat/lng from browser geolocation, else geocode the text.
let city = String(b.city || '').trim();
let lat = Number.isFinite(Number(b.lat)) ? +Number(b.lat).toFixed(4) : '';
let lng = Number.isFinite(Number(b.lng)) ? +Number(b.lng).toFixed(4) : '';
// Treat (0,0) as "geolocation failed / not provided" — Null Island isn't a city.
if (lat === 0 && lng === 0) { lat = ''; lng = ''; }
if (city && (lat === '' || lng === '')) {
  const g = geocode(city);
  city = g.city || city;
  if (lat === '') lat = g.lat;
  if (lng === '') lng = g.lng;
}

const row = {
  session_id: String(b.session_id || ''),
  timestamp: new Date().toISOString(),
  initial_P,
  initial_A,
  final_P,
  final_A,
  final_D,
  match_mode,
  matched_user_id: '',
  match_timestamp: '',
  match_ended_at: '',
  round1_choice: String(selections[0].choice || ''),
  round1_p_delta: Number(selections[0].p_delta) || 0,
  round1_a_delta: Number(selections[0].a_delta) || 0,
  round2_choice: String(selections[1].choice || ''),
  round2_p_delta: Number(selections[1].p_delta) || 0,
  round2_a_delta: Number(selections[1].a_delta) || 0,
  round3_choice: String(selections[2].choice || ''),
  round3_p_delta: Number(selections[2].p_delta) || 0,
  round3_a_delta: Number(selections[2].a_delta) || 0,
  city,
  lat,
  lng
};

if (!row.session_id) {
  throw new Error('session_id is required');
}

return [{ json: row }];

