const raw = String($json.output || $json.text || '').trim();
const cleaned = raw.replace(/```json|```/g,'').trim();
let parsed = null;
try { parsed = JSON.parse(cleaned); } catch(e) {
  const m = cleaned.match(/\{[\s\S]*?\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch(_) {} }
}
const src = $('Compute Vector').first().json;
const row = { ...src };
const goodLat = parsed && parsed.lat != null && Number.isFinite(Number(parsed.lat)) ? Number(parsed.lat) : NaN;
const goodLng = parsed && parsed.lng != null && Number.isFinite(Number(parsed.lng)) ? Number(parsed.lng) : NaN;
const haveCoords = Number.isFinite(goodLat) && Number.isFinite(goodLng) && !(goodLat === 0 && goodLng === 0);
if (haveCoords) {
  row.city = String(parsed.city || src.city || '').trim();
  row.lat = +goodLat.toFixed(4);
  row.lng = +goodLng.toFixed(4);
} else {
  row.city = String(src.city || '').trim();
  row.lat = '';
  row.lng = '';
}
return [{ json: row }];
